import{c as a,Q as e,j as n,m as i}from"./chunks/framework.BBA2dIOt.js";const g=JSON.parse('{"title":"Hardening Caddy","description":"","frontmatter":{},"headers":[],"relativePath":"caddy-hardening.md","filePath":"caddy-hardening.md","lastUpdated":1782764690000}'),t={name:"caddy-hardening.md"};function p(l,s,o,d,r,c){return e(),n("div",null,[...s[0]||(s[0]=[i(`<h1 id="hardening-caddy" tabindex="-1">Hardening Caddy <a class="header-anchor" href="#hardening-caddy" aria-label="Permalink to &quot;Hardening Caddy&quot;">​</a></h1><p>Ember ships with a working <a href="https://github.com/brandonhon/ember/blob/main/deploy/Caddyfile" target="_blank" rel="noreferrer"><code>deploy/Caddyfile</code></a> that terminates TLS and reverse-proxies to the app. It&#39;s a sane baseline, not a locked-down edge. This page covers the hardening worth adding when Ember faces the public internet.</p><h2 id="division-of-responsibility" tabindex="-1">Division of responsibility <a class="header-anchor" href="#division-of-responsibility" aria-label="Permalink to &quot;Division of responsibility&quot;">​</a></h2><p>Caddy and Ember each own part of the security surface. Knowing the split keeps you from duplicating (or worse, contradicting) headers.</p><p><strong>Ember sets on every response</strong> (including 404/405 and errors), so you do <strong>not</strong> need to add these at the proxy:</p><ul><li><code>Content-Security-Policy</code> (locked down — see <a href="/ember/security#transport-proxy-expectations">Security</a>)</li><li><code>X-Frame-Options: DENY</code>, <code>X-Content-Type-Options: nosniff</code></li><li><code>Referrer-Policy: strict-origin-when-cross-origin</code></li><li><code>Permissions-Policy</code>, COOP, CORP</li><li>HSTS — but <strong>only when the request is HTTPS</strong> (direct TLS, or a trusted proxy reporting <code>X-Forwarded-Proto: https</code>)</li></ul><p><strong>Caddy owns the edge:</strong> certificate acquisition and renewal, TLS protocol/cipher selection, the HTTP→HTTPS redirect, request/connection limits, and access logging.</p><p>Because Ember already emits the content-security headers, the proxy&#39;s job is the transport, not re-stamping headers. The one header it makes sense to assert at the edge is HSTS (the bundled Caddyfile already does), so it&#39;s present even on responses Caddy generates itself (e.g. a TLS-level error page before the request reaches Ember).</p><h2 id="trust-the-proxy-correctly" tabindex="-1">Trust the proxy correctly <a class="header-anchor" href="#trust-the-proxy-correctly" aria-label="Permalink to &quot;Trust the proxy correctly&quot;">​</a></h2><p>This is the single most important step, and it&#39;s easy to get wrong in both directions.</p><p>Ember honors <code>X-Real-IP</code> (rate-limit keying) and <code>X-Forwarded-Proto</code> (HTTPS detection for HSTS and <code>Secure</code> cookies) <strong>only</strong> from peers listed in <code>EMBER_TRUSTED_PROXIES</code>. The default is <strong>empty — trust nobody</strong>.</p><ul><li>If <code>EMBER_TRUSTED_PROXIES</code> is <strong>unset</strong> behind Caddy, Ember treats itself as the edge: every request looks like it comes from Caddy&#39;s bridge IP (so the rate limiter keys all clients to one bucket) and <code>X-Forwarded-Proto</code> is ignored.</li><li>If it&#39;s set <strong>too broadly</strong> (e.g. <code>0.0.0.0/0</code>), any peer that can reach Ember directly can forge <code>X-Real-IP</code> to evade the limiter or poison logs.</li></ul><p>Set it to the proxy&#39;s address/range and nothing more. The bundled compose uses the Docker user-defined bridge range:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># deploy/docker-compose.yml — ember service</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">EMBER_TRUSTED_PROXIES</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">\${EMBER_TRUSTED_PROXIES:-172.16.0.0/12}</span></span></code></pre></div><p>On Caddy&#39;s side, tell Caddy which upstream hops to trust when it determines the real client IP (Caddy 2.7+):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>	servers {</span></span>
<span class="line"><span>		trusted_proxies static private_ranges</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><code>private_ranges</code> is a built-in shorthand for the RFC1918 + loopback + CGNAT ranges. If Caddy is itself behind another load balancer or a CDN (Cloudflare), list <strong>that</strong> hop&#39;s ranges instead — otherwise Caddy will report the LB&#39;s IP as the client.</p><h2 id="lock-down-the-admin-api" tabindex="-1">Lock down the admin API <a class="header-anchor" href="#lock-down-the-admin-api" aria-label="Permalink to &quot;Lock down the admin API&quot;">​</a></h2><p>Caddy exposes a local admin API on <code>localhost:2019</code> by default. It can change the running config, including TLS and routing. In a container it&#39;s only reachable from inside the container, but if you don&#39;t use it, turn it off:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>	admin off</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>If you do need it (e.g. for <code>caddy reload</code>), bind it to a unix socket or keep it on loopback and never publish port <code>2019</code>.</p><h2 id="tls" tabindex="-1">TLS <a class="header-anchor" href="#tls" aria-label="Permalink to &quot;TLS&quot;">​</a></h2><p>Caddy&#39;s defaults are already strong: TLS 1.2 + 1.3 only, a modern cipher suite list, automatic OCSP stapling, and automatic certificate renewal. You rarely need to touch them. If a compliance baseline requires TLS 1.3 only:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{$EMBER_HOSTNAME:localhost} {</span></span>
<span class="line"><span>	tls {</span></span>
<span class="line"><span>		protocols tls1.3</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	# ...</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Be deliberate: TLS-1.3-only excludes older clients. For most self-hosted setups the default (1.2+) is the right call.</p><p><strong>Certificates.</strong> Public DNS name + reachable ports 80/443 + a valid <code>CADDY_EMAIL</code> → Caddy fetches a free Let&#39;s Encrypt cert automatically. For a homelab with no public name, use Caddy&#39;s internal CA and trust it on your clients:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{$EMBER_HOSTNAME:localhost} {</span></span>
<span class="line"><span>	tls internal</span></span>
<span class="line"><span>	# ...</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>then run <code>caddy trust</code> on each client. (This line is already present, commented, in the bundled Caddyfile.)</p><p><strong>HSTS preload.</strong> The bundled config sends <code>max-age=31536000; includeSubDomains</code>. Only add <code>; preload</code> and submit to <a href="https://hstspreload.org" target="_blank" rel="noreferrer">hstspreload.org</a> once you&#39;re certain <strong>every</strong> subdomain of the apex will always be HTTPS — preload is hard to undo and applies to the whole domain.</p><h2 id="limit-request-size-and-slow-client-exposure" tabindex="-1">Limit request size and slow-client exposure <a class="header-anchor" href="#limit-request-size-and-slow-client-exposure" aria-label="Permalink to &quot;Limit request size and slow-client exposure&quot;">​</a></h2><p>Ember has its own per-route rate limiting, but the proxy can shed abuse before it reaches the app. Cap the request body (Ember has no endpoint that needs large uploads beyond OPML/TT-RSS imports — a few MB is plenty) and set read/write timeouts to blunt slow-loris:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>	servers {</span></span>
<span class="line"><span>		timeouts {</span></span>
<span class="line"><span>			read_body   10s</span></span>
<span class="line"><span>			read_header 5s</span></span>
<span class="line"><span>			idle        2m</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>		max_header_size 16KB</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>{$EMBER_HOSTNAME:localhost} {</span></span>
<span class="line"><span>	request_body {</span></span>
<span class="line"><span>		max_size 12MB</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	# ...</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Tune <code>max_size</code> up if you import very large OPML/TT-RSS exports.</p><blockquote><p><strong>Rate limiting at the edge</strong> needs the third-party <a href="https://github.com/mholt/caddy-ratelimit" target="_blank" rel="noreferrer"><code>caddy-ratelimit</code></a> plugin, which isn&#39;t in the stock <code>caddy:2-alpine</code> image — you&#39;d build a custom image with <code>xcaddy</code>. Ember&#39;s built-in limiter already covers login, feed-add, and search, so an edge limiter is optional defense-in-depth, not a requirement.</p></blockquote><h2 id="reduce-information-disclosure" tabindex="-1">Reduce information disclosure <a class="header-anchor" href="#reduce-information-disclosure" aria-label="Permalink to &quot;Reduce information disclosure&quot;">​</a></h2><p>Caddy advertises itself with a <code>Server: Caddy</code> header. Strip it if you&#39;d rather not name the proxy:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{$EMBER_HOSTNAME:localhost} {</span></span>
<span class="line"><span>	header -Server</span></span>
<span class="line"><span>	# ...</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Avoid Caddy&#39;s <code>debug</code> global option in production — it logs verbosely, including header values.</p><h2 id="access-logging" tabindex="-1">Access logging <a class="header-anchor" href="#access-logging" aria-label="Permalink to &quot;Access logging&quot;">​</a></h2><p>The stock config doesn&#39;t log requests. Turn on structured access logs so you can spot scans and abuse, and keep them out of the container&#39;s stdout if you ship logs elsewhere:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{$EMBER_HOSTNAME:localhost} {</span></span>
<span class="line"><span>	log {</span></span>
<span class="line"><span>		output file /var/log/caddy/access.log {</span></span>
<span class="line"><span>			roll_size 10MB</span></span>
<span class="line"><span>			roll_keep 10</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>		format json</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	# ...</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Mount a writable volume for <code>/var/log/caddy</code> if you use a file output. Caddy redacts <code>Authorization</code> and cookie values by default; double-check before widening the log format.</p><h2 id="container-hardening" tabindex="-1">Container hardening <a class="header-anchor" href="#container-hardening" aria-label="Permalink to &quot;Container hardening&quot;">​</a></h2><p>Defenses that live in <code>docker-compose.yml</code>, not the Caddyfile:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">caddy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  image</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">caddy:2-alpine</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  read_only</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                 # Caddyfile is mounted :ro; data/config are named volumes</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  cap_drop</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ALL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  cap_add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">NET_BIND_SERVICE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]     </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># needed to bind 80/443</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  security_opt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">no-new-privileges:true</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  tmpfs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/tmp</span></span></code></pre></div><ul><li><code>read_only</code> + <code>tmpfs:/tmp</code> keeps the container filesystem immutable; the <code>caddy-data</code> / <code>caddy-config</code> named volumes remain writable for certs.</li><li><code>cap_drop: ALL</code> then re-add only <code>NET_BIND_SERVICE</code> so Caddy can bind the privileged ports without running as root.</li><li>Keep ports <code>80</code>/<code>443</code> published but <strong>never</strong> publish the admin port <code>2019</code>.</li></ul><h2 id="a-hardened-caddyfile-end-to-end" tabindex="-1">A hardened Caddyfile, end to end <a class="header-anchor" href="#a-hardened-caddyfile-end-to-end" aria-label="Permalink to &quot;A hardened Caddyfile, end to end&quot;">​</a></h2><p>Putting the proxy-side pieces together (container hardening stays in compose):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>	email {$CADDY_EMAIL:admin@localhost}</span></span>
<span class="line"><span>	admin off</span></span>
<span class="line"><span>	{$EMBER_HTTPS_REDIRECT_DIRECTIVE:}</span></span>
<span class="line"><span>	servers {</span></span>
<span class="line"><span>		trusted_proxies static private_ranges</span></span>
<span class="line"><span>		timeouts {</span></span>
<span class="line"><span>			read_body   10s</span></span>
<span class="line"><span>			read_header 5s</span></span>
<span class="line"><span>			idle        2m</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>		max_header_size 16KB</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>{$EMBER_HOSTNAME:localhost} {</span></span>
<span class="line"><span>	encode zstd gzip</span></span>
<span class="line"><span>	header {</span></span>
<span class="line"><span>		Strict-Transport-Security &quot;max-age=31536000; includeSubDomains&quot;</span></span>
<span class="line"><span>		-Server</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	request_body {</span></span>
<span class="line"><span>		max_size 12MB</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	log {</span></span>
<span class="line"><span>		output file /var/log/caddy/access.log {</span></span>
<span class="line"><span>			roll_size 10MB</span></span>
<span class="line"><span>			roll_keep 10</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>		format json</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	reverse_proxy ember:8080 {</span></span>
<span class="line"><span>		header_up Host {host}</span></span>
<span class="line"><span>		header_up X-Real-IP {remote_host}</span></span>
<span class="line"><span>		header_up X-Forwarded-For {remote_host}</span></span>
<span class="line"><span>		header_up X-Forwarded-Proto {scheme}</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>And the matching ember-side requirement, regardless of which extras you adopt:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ember service</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">EMBER_TRUSTED_PROXIES</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">172.16.0.0/12</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # the Caddy↔ember bridge range</span></span></code></pre></div><h2 id="verify" tabindex="-1">Verify <a class="header-anchor" href="#verify" aria-label="Permalink to &quot;Verify&quot;">​</a></h2><p>After reloading Caddy, confirm the edge behaves:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Headers come back over HTTPS, HSTS present, Server stripped</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sI</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://your-host/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -iE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;strict-transport|content-security|x-frame|server&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># HTTP redirects to HTTPS (unless you disabled the redirect)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sI</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://your-host/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> location</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Admin port is not reachable from outside the container</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --max-time</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://your-host:2019/config/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ||</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;admin closed (good)&quot;</span></span></code></pre></div><p>You should see HSTS and Ember&#39;s CSP/<code>X-Frame-Options</code> on the HTTPS response, a <code>301</code> to HTTPS on plain HTTP, and no answer on <code>:2019</code>. Check the rate limiter keys on real client IPs by confirming <code>EMBER_TRUSTED_PROXIES</code> is set — if every request in the logs shows the Caddy bridge IP, it isn&#39;t.</p>`,55)])])}const u=a(t,[["render",p]]);export{g as __pageData,u as default};
